    ingredients: ["1 pound (450g) of trimmed string beans", "2 medium (120g total) carrots", "1 medium (150g) potato", "3 green onions (30g total)", "3 tbsp (45ml) of olive oil", "1 stalk (40g) of celery", "1 medium (120g) seeded and diced tomato", "1 medium (110g) red onion", "1 medium (120g) bell pepper", "1 tsp (5g) of tomato paste", "0.5 tsp (1g) of Berbere", "0.25 tsp (0.5g) of basil", "0.5 tsp (1g) of garlic powder", "1 medium (15g) seeded and sliced hot green pepper (jalapeno)", "0.25 tsp (0.5g) of black pepper", "0.25 tsp (1.5g) of salt"],
