    ingredients: ["1 14-ounce (397g) can fava beans, drained and rinsed", "1 medium yellow (or red) onion, diced [~110g]", "3 tablespoons (45 ml) vegetable oil (or olive oil)", "1 teaspoon (5g) grated ginger", "4 cloves garlic, diced [~12g]", "1 medium tomato (Roma works well), chopped with seeds [~100g]", "2 teaspoons (8g) berbere spice", "½ teaspoon (1g) ground cumin", "2 jalapeños, deseeded and diced [~30g]", "Salt, to taste", "2 tablespoons Garnish (chopped onions, tomatoes, and jalapeños, optional)"],
